export const meta = {
  name: 'init-explore',
  description: '初始化知识库并执行深度代码探索',
  phases: [
    { title: 'Project Scan', detail: '扫描项目文件、依赖、复杂度' },
    { title: 'Architecture Analysis', detail: '分析架构分层和模块关系' },
    { title: 'Domain Knowledge', detail: '提取业务流程和核心概念' },
    { title: 'Learning Path', detail: '生成学习路径' },
    { title: 'Finalize', detail: '生成复用指南并更新索引' }
  ]
}

const projectRoot = '/home/cwtrocks/OpenCoreSDK'
const docsDir = `${projectRoot}/docs/exploration`

// Phase 1: Project Scanning
phase('Project Scan')
log('开始扫描项目结构...')

const projectScan = await agent(
  `扫描项目 ${projectRoot}，生成详细的项目概览。分析：
  1. 项目类型、语言、框架
  2. 文件结构和目录组织
  3. 主要依赖和技术栈
  4. 代码复杂度估算

  输出为结构化的项目概览报告。`,
  {
    label: '扫描项目结构',
    agentType: 'understand-anything:project-scanner',
    schema: {
      type: 'object',
      properties: {
        projectName: { type: 'string' },
        projectType: { type: 'string' },
        languages: { type: 'array', items: { type: 'string' } },
        frameworks: { type: 'array', items: { type: 'string' } },
        buildTools: { type: 'array', items: { type: 'string' } },
        mainDirectories: { type: 'array', items: { type: 'object' } },
        dependencies: { type: 'array', items: { type: 'string' } },
        fileCount: { type: 'number' },
        complexity: { type: 'string' },
        summary: { type: 'string' }
      }
    }
  }
)

// Phase 2: Architecture Analysis
phase('Architecture Analysis')
log('分析架构层次和模块关系...')

const archAnalysis = await agent(
  `分析 ${projectRoot} 的架构。识别：
  1. 主要的架构层次（如：SDK层、JNI层、Native层）
  2. 模块之间的依赖关系
  3. 核心组件和它们的职责
  4. 数据流和控制流

  专注于 Android SDK 的架构模式，特别是 JNI 和 Native 层的交互。`,
  {
    label: '架构分析',
    agentType: 'understand-anything:architecture-analyzer',
    schema: {
      type: 'object',
      properties: {
        layers: { type: 'array', items: { type: 'object' } },
        modules: { type: 'array', items: { type: 'object' } },
        coreComponents: { type: 'array', items: { type: 'object' } },
        dataFlow: { type: 'string' },
        architecturePattern: { type: 'string' }
      }
    }
  }
)

// Phase 3: Domain Knowledge Extraction
phase('Domain Knowledge')
log('提取领域知识和业务流程...')

const domainKnowledge = await agent(
  `从 ${projectRoot} 提取领域知识。分析：
  1. 核心业务概念（如：Coredump、Crash Handler、Signal Handler）
  2. 主要业务流程（如：崩溃捕获流程、coredump生成流程）
  3. 关键算法和技术实现
  4. 与 Android 系统的交互方式

  专注于崩溃分析和 coredump 生成领域的知识。`,
  {
    label: '领域知识提取',
    agentType: 'understand-anything:domain-analyzer',
    schema: {
      type: 'object',
      properties: {
        coreConcepts: { type: 'array', items: { type: 'object' } },
        businessFlows: { type: 'array', items: { type: 'object' } },
        keyAlgorithms: { type: 'array', items: { type: 'string' } },
        systemInteractions: { type: 'array', items: { type: 'string' } }
      }
    }
  }
)

// Phase 4: Learning Path Generation
phase('Learning Path')
log('生成学习路径...')

const learningPath = await agent(
  `为 ${projectRoot} 创建学习路径。设计 5-15 个循序渐进的学习步骤：
  1. 从简单的概念和组件开始
  2. 逐步深入到复杂的交互和流程
  3. 每个步骤包含：标题、描述、关键文件、学习目标

  目标是帮助新开发者快速理解这个 Android 崩溃分析 SDK。`,
  {
    label: '生成学习路径',
    agentType: 'understand-anything:tour-builder',
    schema: {
      type: 'object',
      properties: {
        steps: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              title: { type: 'string' },
              description: { type: 'string' },
              keyFiles: { type: 'array', items: { type: 'string' } },
              learningGoals: { type: 'array', items: { type: 'string' } }
            }
          }
        }
      }
    }
  }
)

// Phase 5: Finalize - Generate documents and update index
phase('Finalize')
log('生成最终文档并更新索引...')

const finalResult = await agent(
  `基于前面的分析结果，完成最后的工作：

  1. 将项目扫描结果写入 ${docsDir}/01-project-overview.md
  2. 将架构分析结果写入 ${docsDir}/02-architecture-analysis.md
  3. 将领域知识写入 ${docsDir}/03-domain-knowledge.md
  4. 将学习路径写入 ${docsDir}/04-learning-path.md
  5. 生成知识复用指南写入 ${docsDir}/05-knowledge-reuse-guide.md（包含如何让 LLM 使用这些文档）
  6. 更新 ${projectRoot}/CLAUDE.md，在文件开头添加知识库索引部分

  项目扫描数据: ${JSON.stringify(projectScan)}
  架构分析数据: ${JSON.stringify(archAnalysis)}
  领域知识数据: ${JSON.stringify(domainKnowledge)}
  学习路径数据: ${JSON.stringify(learningPath)}

  确保生成的文档格式优美、结构清晰，使用 Markdown 格式。
  CLAUDE.md 更新要保留原有内容，只在开头添加知识库索引。`,
  {
    label: '生成文档并更新索引'
  }
)

log('✅ 知识库初始化完成！')

return {
  success: true,
  projectName: projectScan?.projectName,
  docsGenerated: [
    '01-project-overview.md',
    '02-architecture-analysis.md', 
    '03-domain-knowledge.md',
    '04-learning-path.md',
    '05-knowledge-reuse-guide.md'
  ],
  message: '深度代码探索完成，所有文档已生成并更新 CLAUDE.md 索引'
}

