template<typename T>
constexpr T RoundDown(T x, std::remove_reference_t<T> n) {
    return (x & -n);
}

template<typename T>
constexpr T RoundUp(T x, std::remove_reference_t<T> n) {
    return RoundDown(x + n - 1, n);
}

class Opencore {
