创建 `toolchain.cmake`：

```cmake
set(CMAKE_SYSTEM_NAME Android)
set(CMAKE_SYSTEM_VERSION 21)
set(CMAKE_ANDROID_ARCH_ABI arm64-v8a)
set(CMAKE_ANDROID_NDK /path/to/android-ndk)
set(CMAKE_ANDROID_STL_TYPE c++_static)
```

编译：

```bash
mkdir build-android && cd build-android
cmake -DCMAKE_TOOLCHAIN_FILE=../toolchain.cmake ..
make
```

## 与其他崩溃处理库集成

### 与 Breakpad 共存

```cpp
#include "client/linux/handler/exception_handler.h"
#include "opencore/opencore.h"

// Breakpad 回调
bool BreakpadCallback(const google_breakpad::MinidumpDescriptor& descriptor,
                      void* context, bool succeeded) {
    // Breakpad 已生成 minidump

    // 同时生成 OpenCore coredump（更详细）
    Opencore::Dump();

    return succeeded;
}

int main() {
    // 初始化 Breakpad
    google_breakpad::MinidumpDescriptor descriptor("/tmp/minidumps");
    google_breakpad::ExceptionHandler eh(descriptor, nullptr, BreakpadCallback,
                                         nullptr, true, -1);

    // 初始化 OpenCore
    Opencore::SetDir("/tmp/coredumps");
    Opencore::Enable();

    // 业务逻辑
    // ...

    return 0;
}
```

